mapper.select:
SELECT id, create_time, update_time, doctor_user_id, action_type, os_name, ip_address, remark, city
FROM t_doctor_user_log
WHERE doctor_user_id = #{doctorId,jdbcType=VARCHAR}

    AND action_type = #{type}


    AND create_time >= #{beginOfMonth}


    AND create_time <= #{endOfMonth}

ORDER BY create_time DESC
